package com.interview.incidentrca.service;
import com.interview.incidentrca.dto.*;import com.interview.incidentrca.entity.*;import com.interview.incidentrca.enums.Role;import com.interview.incidentrca.exception.BadRequestException;import com.interview.incidentrca.mapper.IncidentMapper;import com.interview.incidentrca.repository.UserRepository;import com.interview.incidentrca.security.JwtService;import lombok.RequiredArgsConstructor;import org.springframework.security.authentication.*;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;import java.time.Instant;
@Service @RequiredArgsConstructor public class AuthService{private final UserRepository users;private final PasswordEncoder encoder;private final AuthenticationManager auth;private final JwtService jwt;private final IncidentMapper mapper;
 public AuthResponse register(RegisterRequest r){if(users.existsByEmail(r.email()))throw new BadRequestException("Email already registered");Role role=r.role()==null?Role.VIEWER:r.role();var u=users.save(User.builder().name(r.name()).email(r.email()).password(encoder.encode(r.password())).role(role).createdAt(Instant.now()).build());return new AuthResponse(jwt.generate(u),mapper.toUser(u));}
 public AuthResponse login(LoginRequest r){auth.authenticate(new UsernamePasswordAuthenticationToken(r.email(),r.password()));var u=users.findByEmail(r.email()).orElseThrow();return new AuthResponse(jwt.generate(u),mapper.toUser(u));}
}
